SeqType classifyProteinLikeAlphabet(std::vector<std::string> &sequences) {
    std::unordered_map<std::string,int> idx;
    for (int i = 0; i < NPAIR; i++) idx[clf_pairs[i]] = i;
    std::vector<double> counts(NPAIR, 0.0);
    for (size_t s = 0; s < sequences.size(); s++) {
        const std::string &seq = sequences[s];
        for (size_t j = 0; j + 1 < seq.size(); j++) {
            std::string p;
            p += (char)toupper(seq[j]); p += (char)toupper(seq[j+1]);
            std::unordered_map<std::string,int>::iterator it = idx.find(p);
            if (it != idx.end()) counts[it->second] += 1.0;
        }
    }
    double tot = 0.0;
    for (int i = 0; i < NPAIR; i++) tot += counts[i];
    if (tot <= 0.0) return SEQ_PROTEIN;
    double pc[NPC];
    for (int k = 0; k < NPC; k++) pc[k] = 0.0;
    for (int i = 0; i < NPAIR; i++) {
        double z = (counts[i] / tot - clf_center[i]) / clf_scale[i];
        for (int k = 0; k < NPC; k++) pc[k] += z * clf_rotation[i][k];
    }
    SeqType types[3] = {SEQ_PROTEIN, SEQ_3DI, SEQ_TEA};
    int best = 0; double bestd = -1.0;
    for (int t = 0; t < 3; t++) {
        double d = 0.0;
        for (int k = 0; k < NPC; k++) { double e = clf_centroid[t][k] - pc[k]; d += e*e; }
        if (bestd < 0.0 || d < bestd) { bestd = d; best = t; }
    }
    return types[best];
}
